    node.warn("SF_Init_4 : INIT_SESSION non validée, RESET bloqué");
    return null;
}

// ---- 2. Chargement dictionnaire ----
const enrichedVars = global.get("enrichedVars");

if (!enrichedVars) {
    node.error("SF_Init_4 : enrichedVars absent");
    return null;
}

// ---- 3. Préparation messages VPIV ----
let vpivArduino = [];
let vpivSE = [];

/*
 * Règle :
 * - Toute variable ayant une signification Arduino → Arduino
 * - Toute variable logique / applicative → SE
 * À ce stade, on envoie TOUT, le filtrage fin viendra plus tard
 */

Object.keys(enrichedVars).forEach(varKey => {

    const varDef = enrichedVars[varKey];
    if (!varDef || !varDef.abbrVarG) return;

    const abbrVar = varDef.abbrVarG;
    const instances = varDef.instances || ["*"];
    const props = varDef.proprietes || [];

    instances.forEach(inst => {
        props.forEach(prop => {

            const abbrP = prop.abbrP;
            if (!abbrP || !prop.valeurs) return;

            let value = null;

            if (prop.valeurs[inst] !== undefined) {
                value = prop.valeurs[inst];
            } else if (prop.valeurs["*"] !== undefined) {
                value = prop.valeurs["*"];
            }

            if (value === null || value === undefined) return;

            const vpivMsg = {
                v: abbrVar,
                i: inst,
                p: abbrP,
                val: value
            };

            // Heuristique simple (à raffiner plus tard)
            if (["mtr", "srv", "us", "mic", "ledring", "ledrub", "CfgS"].includes(abbrVar)) {
                vpivArduino.push(vpivMsg);
            } else {
                vpivSE.push(vpivMsg);
            }
        });
    });
});

// ---- 4. Positionnement modeRZ = VEILLE ----
const VEILLE = 1;

global.set("configuration", {
    ...(global.get("configuration") || {}),
    instances: {
        "*": {
            mode_op: VEILLE
        }
    }
});

