// 🔄 Fonctions utilitaires existantes
const storeDefault = "default";
const storeFile = "file";

// 🔄 Valeur par défaut selon le type
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

// 🔄 Conversion string → typé (avec gestion des valeurs par défaut)
function convertFromString(value, type, defaultVal) {
    if (value === null || value === undefined) {
        return defaultVal !== undefined ? convertFromString(defaultVal, type) : defaultForType(type);
    }
    try {
        switch (type) {
            case "int": return parseInt(value, 10);
            case "number": return parseFloat(value);
            case "boolean": return (value === true || value === "true");
            case "string": return String(value);
            case "array": return Array.isArray(value) ? value : JSON.parse(value);
            case "object": return typeof value === "object" ? value : JSON.parse(value);
            case "date": return new Date(value);
            default: return value;
        }
    } catch (err) {
        node.error(`Erreur de conversion (${type}): ${err.message} (valeur: ${value})`, msg);
        return defaultForType(type);
    }
}

// 🔄 Fonction principale : chargeEnrichedVarsToMemory
function chargeEnrichedVarsToMemory() {
    // Supprimer enrichedVars du stockage par défaut
    global.set("enrichedVars", undefined, storeDefault);

    // Charger enrichedVars depuis le fichier
    let enrichedVars = global.get("enrichedVars", storeFile) || {};
    if (Object.keys(enrichedVars).length === 0) {
        node.error("⚠️ Aucune donnée enrichedVars trouvée dans le stockage fichier.", msg);
        node.status({ fill: "red", shape: "ring", text: "Échec : données manquantes" });
        return false;
    }

    // Parcourir chaque variable dans enrichedVars
    Object.entries(enrichedVars).forEach(([key, e]) => {
        const instances = e.instances || ["*"];
        const props = e.proprietes || [];
        let variable = {};

        // Parcourir les instances
        instances.forEach(instance => {
            variable[instance] = {};
            props.forEach(prop => {
                const name = prop.nomP;
                const type = prop.typeP;
                const rawValue = prop.valeurs?.[instance];
                const defaultVal = prop.valeurs?.["*"];
                variable[instance][name] = convertFromString(rawValue, type, defaultVal);
            });
        });

        // Ajouter les métadonnées (abréviations, etc.)
        if (e.abbrVarG) variable._abbrVarG = e.abbrVarG;
        if (e.indexInstances) variable._indexInstances = e.indexInstances;

        // Stocker dans les variables globales
        if (instances.length === 1 && instances[0] === "*") {
            global.set(key, variable["*"], storeDefault);
        } else {
            global.set(key, variable, storeDefault);
        }
    });

    node.status({ fill: "green", shape: "dot", text: "✅ enrichedVars chargé en mémoire" });
    node.send({ payload: "Chargement terminé" });
    return true;
}

// 🔄 Appel de la fonction
chargeEnrichedVarsToMemory();
msg.info = "✅ Initialisation enrichie depuis enrichedVars (file) terminée.";
return msg;

