function loadEnrichedVarsToMemory(enrichedVars) {
    let globalMemory = {};
    for (const [varName, varData] of Object.entries(enrichedVars)) {
        globalMemory[varName] = { _types: {} };
        // Stocker les types
        for (const prop of varData.proprietes) {
            globalMemory[varName]._types[prop.nomP] = prop.typeP;
        }
        // Stocker les valeurs
        for (const instance of varData.instances) {
            globalMemory[varName][instance] = {};
            for (const prop of varData.proprietes) {
                globalMemory[varName][instance][prop.nomP] = prop.valeurs[instance];
            }
        }
    }
    return globalMemory;
}

