// Fonction : setGlobalVar
// Met à jour une variable globale en vérifiant le type
function setGlobalVar(globalVarName, instance, propName, value) {
    const globalMemory = global.get('enrichedVarsMemory') || {};
    if (!globalMemory[globalVarName] || !globalMemory[globalVarName]._types[propName]) {
        node.error(`Variable ou propriété introuvable : ${globalVarName}.${propName}`, msg);
        return false;
    }

    // Récupérer le type attendu
    const expectedType = globalMemory[globalVarName]._types[propName];
    // Caster la valeur
    const castedValue = castValue(value, expectedType);
    if (castedValue === null) return false;

    // Mettre à jour la valeur
    if (!globalMemory[globalVarName][instance]) {
        globalMemory[globalVarName][instance] = {};
    }
    globalMemory[globalVarName][instance][propName] = castedValue;
    global.set('enrichedVarsMemory', globalMemory);
    return true;
}

