/* loadAndValidateVars
   Node-RED Function node : charge et valide le fichier JSON des variables (variables.json)
   - Entrée : msg.payload (string JSON) ou file-in connecté
   - Sorties : [ mqttAlertMsg, debugResultMsg ]
   - Actions :
       * parse JSON
       * normalise types (integer -> number, cast booleans)
       * déduplique instances
       * vérifie unicité abbrVarG globalement
       * vérifie unicité abbrP par variable et abbrSsP par propriété
       * construit :
           - global.set('varsDefinitions', varsDefinitions)  // keyed by abbrVarG
           - global.set('runtimeVars', runtimeVars)          // initial runtime state
       * retourne un message de statut en sortie 1 et publie un mqtt alert sur sortie 0 (si erreurs)
   - Adapte MQTT_ALERT_TOPIC si besoin.
*/

const MQTT_ALERT_TOPIC = "SP/I/urgent/vars_check"; // topic pour les alertes critiques de validation

// helpers
function toBool(v) {
    if (typeof v === "boolean") return v;
    if (v === null || v === undefined) return false;
    const s = String(v).trim().toLowerCase();
    return (s === "true" || s === "1");
}
function isIntegerString(s) {
    return /^-?\d+$/.test(String(s));
}
function safeParseJSON(s) {
    try { return JSON.parse(s); } catch(e){ return null; }
}
function uniqArray(arr) {
    return Array.from(new Set(arr));
}

// Begin
let raw = msg.payload;
if (typeof raw === "string") {
    try { raw = JSON.parse(raw); } catch(e) {
        node.error("loadAndValidateVars: payload must be JSON or a string containing JSON");
        return null;
    }
}
const varsFile = raw || {};
const errors = [];
const warnings = [];
// Lookup tables to build
const mapVarAbbrToFull = {};
const mapPropAbbrToFull = {};
const mapSubPropAbbrToFull = {};

// Iterate variables (keys are long names)
Object.keys(varsFile).forEach((key) => {
    const v = varsFile[key];
    const nomVarG = v.nomVarG || key;
    const abbrVarG = v.abbrVarG;
    if(!abbrVarG) {
        errors.push(`Variable ${nomVarG} missing abbrVarG`);
        return;
    }
    // abbrVarG unique global
    if(mapVarAbbrToFull[abbrVarG]) {
        errors.push(`abbrVarG collision: '${abbrVarG}' used by ${mapVarAbbrToFull[abbrVarG]} and ${nomVarG}`);
    } else {
        mapVarAbbrToFull[abbrVarG] = nomVarG;
    }
    // instances dedupe
    if(Array.isArray(v.instances)) v.instances = uniqArray(v.instances);
    else v.instances = ["*"];
    // properties
    mapPropAbbrToFull[nomVarG] = {};
    mapSubPropAbbrToFull[nomVarG] = {};
    if(!Array.isArray(v.proprietes)) {
        warnings.push(`Variable ${nomVarG} has no 'proprietes' array; creating empty.`);
        v.proprietes = [];
    }
    v.proprietes.forEach((p) => {
        const nomP = p.nomP || "__unknown__";
        const abbrP = p.abbrP;
        let typeP = (p.typeP || 'string').toLowerCase();
        if(typeP === 'integer') typeP = 'number';
        if(typeP === 'float') {
            warnings.push(`Variable ${nomVarG}.${nomP} requests float: converting to 'number' (integers only).`);
            typeP = 'number';
        }
        p.typeP = typeP;
        // abbrP uniqueness within the variable
        if(!abbrP) {
            errors.push(`Variable ${nomVarG} property ${nomP} missing abbrP`);
        } else if(mapPropAbbrToFull[nomVarG][abbrP]) {
            errors.push(`Property abbr collision in ${nomVarG}: abbrP '${abbrP}' used for ${mapPropAbbrToFull[nomVarG][abbrP]} and ${nomP}`);
        } else {
            mapPropAbbrToFull[nomVarG][abbrP] = nomP;
        }
        // sub props (schema)
        mapSubPropAbbrToFull[nomVarG][nomP] = {};
        if(Array.isArray(p.schema)) {
            p.schema.forEach((sp) => {
                const nomSsP = sp.nomSsP;
                const abbrSsP = sp.abbrSsP || (nomSsP ? nomSsP.substring(0,3) : undefined);
                if(!abbrSsP) {
                    errors.push(`Variable ${nomVarG} property ${nomP} has schema entry missing abbrSsP/nomSsP`);
                } else {
                    if(mapSubPropAbbrToFull[nomVarG][nomP][abbrSsP]) {
                        errors.push(`Sub-property abbr collision in ${nomVarG}.${nomP}: '${abbrSsP}'`);
                    } else {
                        mapSubPropAbbrToFull[nomVarG][nomP][abbrSsP] = nomSsP;
                    }
                }
            });
        }
        // normalize default valeurs
        if(typeof p.valeurs === 'object' && p.valeurs !== null) {
            Object.keys(p.valeurs).forEach((inst) => {
                let val = p.valeurs[inst];
                if(typeP === 'boolean') {
                    if(typeof val === 'string') p.valeurs[inst] = toBool(val);
                } else if(typeP === 'number') {
                    if(typeof val === 'string' && isIntegerString(val)) p.valeurs[inst] = Number(val);
                    else if(typeof val === 'string') {
                        warnings.push(`Variable ${nomVarG}.${nomP} instance ${inst} has non-integer string '${val}', keeping as string`);
                    }
                } else if(typeP === 'object' || typeP === 'array') {
                    if(typeof val === 'string') {
                        const parsed = safeParseJSON(val);
                        if(parsed === null) {
                            errors.push(`Variable ${nomVarG}.${nomP} instance ${inst} value is not valid JSON for type ${typeP}`);
                        } else {
                            p.valeurs[inst] = parsed;
                        }
                    }
                }
            });
        } else {
            // create valeur entries for instances
            p.valeurs = p.valeurs || {};
            v.instances.forEach((inst) => { if(!(inst in p.valeurs)) p.valeurs[inst] = null; });
            warnings.push(`Variable ${nomVarG}.${nomP} had incomplete 'valeurs'; filled missing instances with null`);
        }
    }); // end properties
}); // end variables loop

// Build varsDefinitions keyed by abbrVarG
const varsDefinitions = {};
Object.keys(varsFile).forEach((k) => {
    const def = varsFile[k];
    if(def.abbrVarG) varsDefinitions[def.abbrVarG] = def;
});
// Build runtimeVars initial skeleton (copies default '*')
const runtimeVars = {};
Object.keys(varsDefinitions).forEach((abbr) => {
    const def = varsDefinitions[abbr];
    runtimeVars[abbr] = { instances: {}, _meta: def };
    def.instances.forEach((inst) => {
        runtimeVars[abbr].instances[inst] = {};
        def.proprietes.forEach((p) => {
            const abbrP = p.abbrP;
            let vval = null;
            if(p.valeurs && (inst in p.valeurs)) vval = p.valeurs[inst];
            else if(p.valeurs && ('*' in p.valeurs)) vval = p.valeurs['*'];
            runtimeVars[abbr].instances[inst][abbrP] = vval;
        });
    });
});

// Set globals
global.set('varsDefinitions', varsDefinitions);
global.set('runtimeVars', runtimeVars);

// Prepare result
const result = {
    ok: errors.length === 0,
    errors, warnings,
    counts: { variables: Object.keys(varsDefinitions).length }
};

// Return: output 0 = mqtt publish message (alert or ok), output 1 = debug result
if(errors.length > 0) {
    const alertMsg = { topic: MQTT_ALERT_TOPIC, payload: JSON.stringify({ type: "vars_validation_error", errors, warnings, counts: result.counts }) };
    return [alertMsg, { payload: result }];
} else {
    const okMsg = { topic: "SP/I/normal/vars_check", payload: JSON.stringify({ type: "vars_validation_ok", warnings, counts: result.counts }) };
    return [okMsg, { payload: result }];
}

/* parseVPIV
   Fonction Node-RED pour décoder les messages VPIV de la forme :
     $<cat>:<varAbbr>:<propAbbr>:<inst>:<value>#

   - Elle s'attend à ce que msg.topic soit de type "arduino/..." ou "SE/..." 
     et que msg.payload soit la chaîne brute.
   - Utilise global.varsDefinitions pour trouver typeP et convertir la valeur en conséquence.
   - Met à jour global.runtimeVars avec la valeur analysée.
   - Émet un objet msg.vpiv contenant {cat,varAbbr,propAbbr,inst,value,typeP,topic}
*/
// Helper: safe JSON parse
function safeParse(s) {
    try { return JSON.parse(s); } catch (e) { return null; }
}
const payload = (msg.payload || "").toString().trim();
const m = payload.match(/^\$(.+?):(.+?):(.+?):(.+?):([\s\S]+?)#$/);
if (!m) {
    node.warn("parseVPIV: bad payload format: " + payload);
    return null;
}
const [_, cat, varAbbr, propAbbr, inst, rawVal] = m;

// fetch definitions
const varsDefinitions = global.get('varsDefinitions') || {};
const varDef = varsDefinitions[varAbbr];
let typeP = 'string';
if (varDef && Array.isArray(varDef.proprietes)) {
    const prop = varDef.proprietes.find(p => p.abbrP === propAbbr || p.nomP === propAbbr);
    if (prop && prop.typeP) typeP = prop.typeP;
}

// cast rawVal according to typeP
let value;
try {
    if (typeP === 'number') {
        // allow numeric strings; if non-numeric, warn and keep string
        if (/^[-]?\d+$/.test(rawVal.trim())) value = Number(rawVal);
        else { node.warn("parseVPIV: expected number but got '" + rawVal + "'"); value = Number(rawVal) || rawVal; }
    } else if (typeP === 'boolean') {
        const s = rawVal.trim().toLowerCase();
        value = (s === 'true' || s === '1');
    } else if (typeP === 'object' || typeP === 'array') {
        // try JSON.parse
        const parsed = safeParse(rawVal);
        if (parsed === null) {
            node.warn("parseVPIV: expected JSON for type " + typeP + " but parsing failed: " + rawVal);
            value = rawVal;
        } else value = parsed;
    } else if (typeP === 'time') {
        // epoch millis -> number
        if (/^\d+$/.test(rawVal.trim())) value = Number(rawVal);
        else { node.warn("parseVPIV: expected epoch millis for time, got: " + rawVal); value = rawVal; }
    } else {
        // string fallback
        value = rawVal;
    }
} catch (e) {
    node.warn("parseVPIV: casting error: " + e.message);
    value = rawVal;
}

// update runtimeVars in global
const runtimeVars = global.get('runtimeVars') || {};
if (!runtimeVars[varAbbr]) {
    // if unknown var, create a minimal runtime entry so flows can still use it
    runtimeVars[varAbbr] = { instances: {}, _meta: varDef || null };
}
if (!runtimeVars[varAbbr].instances[inst]) runtimeVars[varAbbr].instances[inst] = {};
runtimeVars[varAbbr].instances[inst][propAbbr] = value;
global.set('runtimeVars', runtimeVars);

// output msg.vpiv for downstream flows
msg.vpiv = { cat, varAbbr, propAbbr, inst, value, typeP, topic: msg.topic };
msg.payload = msg.vpiv;
return msg;

/* encodeVPIV
   Build a VPIV payload from msg.payload object:
   expected input: msg.payload = { cat:'V', varAbbr:'DVar', propAbbr:'val', inst:'*', value: ... }
   Output: msg.payload = "$<cat>:<varAbbr>:<propAbbr>:<inst>:<value>#"
   Handles JSON stringify for object/array, boolean->'true'/'false', numbers -> integer strings.
*/
const obj = msg.payload;
if (!obj || !obj.varAbbr || !obj.propAbbr) {
    node.error("encodeVPIV: input must be object with varAbbr and propAbbr");
    return null;
}
let valStr;
if (typeof obj.value === 'object') {
    try { valStr = JSON.stringify(obj.value); }
    catch (e) { node.error("encodeVPIV: JSON stringify failed: " + e.message); return null; }
} else if (typeof obj.value === 'boolean') {
    valStr = obj.value ? "true" : "false";
} else {
    valStr = String(obj.value);
}
// sanitize: remove any leading/trailing whitespace that could break parsing
valStr = valStr.trim();
// construct payload
msg.payload = `$${obj.cat || 'V'}:${obj.varAbbr}:${obj.propAbbr}:${obj.inst || '*'}:${valStr}#`;
return msg;

