    }

    if (act.type === "SERVO") {
        if (!["FIXE", "VEILLE", "DEPLACEMENT"].includes(modeRZ)) {
            refused.push({action: act, reason: "MODE_INCOMPATIBLE"});
            continue;
        }
    }

    accepted.push(act);
}

if (accepted.length === 0) {
    msg.status = "REFUSED";
    msg.refused = refused;
    return [null, msg];
}

msg.status = "ACCEPTED";
msg.acceptedActions = accepted;
return [msg, null];

let vpivs = [];

for (let act of msg.acceptedActions) {
    vpivs.push({
        vpiv: {
            app: act.device,
            var: act.type,
            prop: act.target || "",
            value: act.value || {
                color: act.color,
                mode: act.mode
            }
        }
    });
}

msg.vpivs = vpivs;
return msg;

// ============================================
// RZ_VPIV_Encoder_Dispatcher_V1
// Encode chaque action en trame VPIV
// ============================================

if (!msg.command || !Array.isArray(msg.command.actions)) {
    return null;
}

let outArduino = [];
let outSE = [];

msg.command.actions.forEach(action => {
    // Sécurité minimale
    if (!action.cat || !action.module || !action.prop || action.value === undefined) {
        return;
    }

    let inst = action.inst || "*";
    let vpiv = `$${action.cat}:${action.module}:${action.prop}:${inst}:${action.value}#`;

    let outMsg = {
        payload: vpiv,
        vpiv: {
            cat: action.cat,
            module: action.module,
            prop: action.prop,
            inst: inst,
            value: action.value
        }
    };

    if (action.device === "ARDUINO") {
        outArduino.push(outMsg);
    } else if (action.device === "SE") {
        outSE.push(outMsg);
    }
});

return [outArduino, outSE];

