if (msg.payload.includes("En attente de configuration")) {
    // Préparation de la configuration (sans commentaires)
    var defaultConfig = {
        global: {
            modeRZ: 1,
            typePtge: 0
        },
        Gyro: {
            modeGyro: "OFF",
            frequence: 10,
            modeRZ: [2, 3]
        }
    };

    // Découpage en chunks
    var configStr = JSON.stringify(defaultConfig);
    var chunkSize = 100;

    for (var i = 0; i < Math.ceil(configStr.length / chunkSize); i++) {
        var chunk = configStr.substring(i * chunkSize, (i + 1) * chunkSize);
        msg.topic = "SE/config/chunk";
        msg.payload = "$F:CfgS:chunk:" + i + ":" + chunk + "#";
        node.send(msg);
    }

    return null;
}
